class Solution:
    def maxScore(self, n, k, stayScore, travelScore):
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def solve(day, city):
            if day == k:
                return 0
            best = stayScore[day][city] + solve(day + 1, city)
            for dest in range(n):
                if dest != city:
                    cand = travelScore[city][dest] + solve(day + 1, dest)
                    if cand > best:
                        best = cand
            return best

        return max(solve(0, c) for c in range(n))

