class Solution:
    def maxScore(self, n: int, k: int, stayScore: List[List[int]], travelScore: List[List[int]]) -> int:
        dp = [0] * n
        for c in range(n):
            best = stayScore[0][c]
            for p in range(n):
                if p != c and travelScore[p][c] > best:
                    best = travelScore[p][c]
            dp[c] = best
        for day in range(1, k):
            new_dp = [0] * n
            for c in range(n):
                best = dp[c] + stayScore[day][c]
                for p in range(n):
                    if p != c:
                        cand = dp[p] + travelScore[p][c]
                        if cand > best:
                            best = cand
                new_dp[c] = best
            dp = new_dp
        return max(dp)

