var maxScore = function(n, k, stayScore, travelScore) {
    let dp = new Array(n).fill(0);
    for (let c = 0; c < n; c++) {
        let best = stayScore[0][c];
        for (let p = 0; p < n; p++) {
            if (p !== c && travelScore[p][c] > best) best = travelScore[p][c];
        }
        dp[c] = best;
    }
    for (let day = 1; day < k; day++) {
        const newDp = new Array(n).fill(0);
        for (let c = 0; c < n; c++) {
            let best = dp[c] + stayScore[day][c];
            for (let p = 0; p < n; p++) {
                if (p !== c) {
                    const cand = dp[p] + travelScore[p][c];
                    if (cand > best) best = cand;
                }
            }
            newDp[c] = best;
        }
        dp = newDp;
    }
    return Math.max(...dp);
};
